            aOrbiterF = (((aWandererA + RotL64(aScatter, 27U)) + RotL64(aCarry, 51U)) + 0xDF8B65D7A11795D9ULL) + aPhaseAOrbiterAssignSaltE[(((31U - aIndex) + 10U)) & S_SALT1];
