            aOrbiterK = (aOrbiterK + aOrbiterE) + 0x72C68DA87284D4E0ULL;
            aOrbiterI = ((aOrbiterI ^ aOrbiterK) ^ 0x0D30277F2C3B13CDULL) ^ aPhaseAOrbiterUpdateSaltF[((aIndex + 5U)) & S_SALT1];
