            //
            aOrbiterI = ((aOrbiterI + aOrbiterD) + 0x59AB50170E816994ULL) + aPhaseAOrbiterUpdateSaltE[(((31U - aIndex) + 8U)) & S_SALT1];
            aOrbiterF = ((aOrbiterF ^ aOrbiterI) ^ 0x978A2FE9F84E399AULL) ^ aPhaseAOrbiterUpdateSaltB[(((31U - aIndex) + 21U)) & S_SALT1];
