            aOrbiterK = ((aOrbiterK ^ aOrbiterJ) ^ 0xCE322E86E68E5541ULL) ^ aPhaseAOrbiterUpdateSaltB[((aIndex + 6U)) & S_SALT1];
            aOrbiterK = RotL64((aOrbiterK * 0xA4B4989E933F6171ULL), 57U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterA) + 0x4068670B9D813A67ULL;
            aOrbiterJ = ((aOrbiterJ ^ aOrbiterF) ^ 0xABA0884B2F68B3C3ULL) ^ aPhaseAOrbiterUpdateSaltA[(((31U - aIndex) + 23U)) & S_SALT1];
            aOrbiterJ = RotL64((aOrbiterJ * 0xCAB270DC0F60B28DULL), 51U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterD) + 0xF4DBED92D49F25E5ULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterK) ^ 0x2B729B0B7C8A6164ULL;
