            //
            aOrbiterA = (aWandererH + RotL64(aPrevious, 5U)) + 0xAF25B31B4267E8D1ULL;
            aOrbiterH = (aWandererD + RotL64(aScatter, 43U)) + 0x0C4E12B7B6409D94ULL;
            aOrbiterF = ((aWandererJ + RotL64(aCross, 41U)) + RotL64(aCarry, 43U)) + 0x5E0C226AD08CA348ULL;
            aOrbiterK = ((aWandererG + RotL64(aIngress, 14U)) + RotL64(aCarry, 35U)) + 0x28F4DF8F8B4C9673ULL;
            aOrbiterE = (aWandererF + RotL64(aScatter, 37U)) + 0x3A08622E922E0A3EULL;
            aOrbiterJ = (aWandererK + RotL64(aIngress, 23U)) + 0xFC7CDCD869246E52ULL;
            aOrbiterD = ((aWandererA + RotL64(aPrevious, 3U)) + 0x833ACA858507DC6CULL) + aPhaseGOrbiterAssignSaltC[((aIndex + 19U)) & S_SALT1];
            aOrbiterI = (aWandererE + RotL64(aCross, 26U)) + 0xE8202FECBED744CAULL;
            aOrbiterB = ((aWandererC + RotL64(aIngress, 47U)) + 0xB9C8E9DD998A3669ULL) + aPhaseGOrbiterAssignSaltE[(((31U - aIndex) + 25U)) & S_SALT1];
            aOrbiterC = (aWandererI + RotL64(aCross, 11U)) + 0xDF4EFD0B0ACE05D7ULL;
            aOrbiterG = ((aWandererB + RotL64(aPrevious, 19U)) + RotL64(aCarry, 53U)) + 0x4D48B32D2692EFACULL;
            //
            aOrbiterA = (aOrbiterA + aOrbiterH) + 0x4F80C8E76348B464ULL;
