            aOrbiterK = RotL64((aOrbiterK * 0xCF2923498F764487ULL), 53U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterI) + 0xD633BA291C2967EAULL) + aPhaseGOrbiterUpdateSaltA[((aIndex + 17U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterD) ^ 0xCE2540E96559991DULL;
            aOrbiterB = RotL64((aOrbiterB * 0x809309A328339B17ULL), 35U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterB) + 0x01929BBCB9AB50ADULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterC) ^ 0x2C65F6CDC84A6A6DULL;
            aOrbiterH = RotL64((aOrbiterH * 0xC8DE2534EF02E3C1ULL), 11U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterJ) + 0x734D49E90967376DULL;
            aOrbiterG = (aOrbiterG ^ aOrbiterB) ^ 0xCFD866B7194C80C8ULL;
