            //
            aIngress = RotL64(aOrbiterB, 29U) ^ aOrbiterK;
            aIngress = aIngress + (RotL64(aOrbiterG, 37U) ^ aOrbiterI);
            aIngress = aIngress + (RotL64(aOrbiterA, 20U) ^ aOrbiterC);
            aIngress = aIngress + (aOrbiterF ^ RotL64(aOrbiterH, 3U));
            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterE, 13U));
