            //
            aScatter = (RotL64(aCarry, 54U) ^ RotL64(aIngress, 5U)) + (RotL64(aPrevious, 21U) ^ RotL64(aCross, 35U));
            aScatter = TwistMix64::DiffuseA(aScatter);
            //
            aOrbiterF = (((aWandererH + RotL64(aCross, 50U)) + RotL64(aCarry, 53U)) + 0x63C880A6A8255C9FULL) + aPhaseHOrbiterAssignSaltD[((aIndex + 3U)) & S_SALT1];
            aOrbiterC = (aWandererB + RotL64(aScatter, 41U)) + 0x08D4B7177B091E75ULL;
            aOrbiterE = (aWandererK + RotL64(aPrevious, 19U)) + 0xCC67640FEE9E24D2ULL;
            aOrbiterJ = (aWandererG + RotL64(aIngress, 13U)) + 0xD83C2121AAB78A83ULL;
            aOrbiterB = (aWandererI + RotL64(aCross, 37U)) + 0x0446EFC2271E73BAULL;
            aOrbiterA = (aWandererJ + RotL64(aScatter, 29U)) + 0xC99F40B1F8998B52ULL;
            aOrbiterG = (aWandererD + RotL64(aIngress, 3U)) + 0xA6A478F7E8C24BC1ULL;
            aOrbiterK = (((aWandererF + RotL64(aPrevious, 23U)) + RotL64(aCarry, 43U)) + 0x8B8431718D15D352ULL) + aPhaseHOrbiterAssignSaltE[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterH = ((aWandererC + RotL64(aScatter, 46U)) + RotL64(aCarry, 23U)) + 0x0247A706F81D86C7ULL;
            //
            aOrbiterF = (aOrbiterF + aOrbiterC) + 0x5D60FDE3748C2BCDULL;
            aOrbiterE = (aOrbiterE ^ aOrbiterF) ^ 0x1766B0305B8CDCC6ULL;
            aOrbiterE = RotL64((aOrbiterE * 0x3D2D932088293EC9ULL), 43U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterB) + 0x3484F1CD4B04AB3FULL;
            aOrbiterF = (aOrbiterF ^ aOrbiterJ) ^ 0x25AA72274E1D4B2DULL;
            aOrbiterF = RotL64((aOrbiterF * 0xADC765F4CCB2E68FULL), 27U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterJ) + 0xAEC2A93BA8FA5FAFULL) + aPhaseHOrbiterUpdateSaltF[((aIndex + 23U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterA) ^ 0xDF5191A562F3D7C8ULL;
            aOrbiterG = RotL64((aOrbiterG * 0x718A5731079FD785ULL), 47U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterA) + 0x20C13C2B2301E0A2ULL;
            aOrbiterC = ((aOrbiterC ^ aOrbiterB) ^ 0xEB8A9B39C407EC59ULL) ^ aPhaseHOrbiterUpdateSaltC[(((31U - aIndex) + 24U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 0xD5054350A4AF4167ULL), 3U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterH) + 0x1E812B08213EEE04ULL) + aPhaseHOrbiterUpdateSaltE[((aIndex + 9U)) & S_SALT1];
            aOrbiterJ = (aOrbiterJ ^ aOrbiterK) ^ 0x4575CA4CAA5FBB84ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0xE51AA6D42FB70799ULL), 51U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterE) + 0xD010695A72A498BEULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterH) ^ 0xF10FBC302DF01134ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x1EF9EC0519508BC9ULL), 23U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterK) + 0x792AD3EBAEDF1E6DULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterE) ^ 0x3E76B32B726A8C9DULL) ^ aPhaseHOrbiterUpdateSaltB[(((31U - aIndex) + 8U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0xB8EF2B17503C339DULL), 11U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterG) + 0xA63C58B69DDAAD4CULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterC) ^ 0xF0C2D0E3C3439329ULL;
            aOrbiterK = RotL64((aOrbiterK * 0x6E0228E446D47A43ULL), 57U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterF) + 0xE2EB1C106E5AD1E9ULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterG) ^ 0x0295762524E6E45EULL;
            aOrbiterH = RotL64((aOrbiterH * 0xD1AC17C89DAE6D09ULL), 35U);
            //
            aIngress = aOrbiterA ^ RotL64(aOrbiterH, 47U);
